args.sparql:
SELECT ?orgLabel WHERE {
  wd:Q160549 wdt:P2018 wd:Q3724 .
  wd:Q160549 wdt:P31 wd:Q207188 .
  wd:Q160549 rdfs:label ?orgLabel .
  FILTER (lang(?orgLabel) = 'en')
}

SELECT ?locationLabel WHERE {
  wd:Q160549 wdt:P740 ?location.
  ?location rdfs:label ?locationLabel.
  FILTER (lang(?locationLabel) = 'en')
}
